#include <unordered_map>
#include <vector>
#include <string>

using namespace std;

vector<int> diffWaysToCompute(string expression) {
    unordered_map<char, vector<int>> operators;
    vector<int> results;

    // Initialize operators map
    operators['+'] = {1, 2};
    operators['-'] = {1, -2};
    operators['*'] = {2, -2};

    // Parse expression and build a tree
    stack<char> stack;
    for (char c : expression) {
        if (operators.count(c)) {
            stack.push(c);
        } else {
            int num = stoi(string(stack.top(), stack.top() + operators[c][0]);
            stack.pop();
            results.push_back(num);
        }
    }

    // Process the stack
    while (!stack.empty()) {
        int num = stoi(string(stack.top(), stack.top() + operators[stack.top()][1]);
        stack.pop();
        results.push_back(num);
    }

    return results;
}
